        {
          "id": "s:a73690cfed897c3fb795876575b3cb8a870361f3",
          "name": "Tequila Herradura (officially Grupo Industrial Herradura) is a tequila distiller located in Amatitán, Jalisco, Mexico.",
          "category": "Sentence"
        },
        {
          "id": "s:abd241ff9dd83427804f72da8df9ec4181732a15",
          "name": " Today it is owned by US beverage maker Brown-Forman, but the tequila is still made in the same place and facilities under a Mexican subsidiary.",
          "category": "Sentence"
        },
        {
          "id": "s:83ac6bb6ac22ff8eb220c77b71413b67e28b0624",
          "name": "The Brown-Forman Corporation is one of the largest American-owned companies in the spirits and wine business.",
          "category": "Sentence"
        },
        {
          "id": "s:11e6ffd3f6ef752f3f7a66a34c72c9b59206e16d",
          "name": " Based in Louisville, Kentucky, it manufactures several well known brands throughout the world, including Jack Daniel's, Early Times, Old Forester, Woodford Reserve, Canadian Mist, GlenDronach, BenRiach, Glenglassaugh, Finlandia, Herradura, Korbel, and Chambord.",
          "category": "Sentence"
        }
